const wait = ms => new Promise(r => setTimeout(r, ms));
function copyText(text) {
  function fallback() {
    try {
      const ta = document.createElement("textarea");
      ta.value = text;
      ta.style.position = "fixed";
      ta.style.opacity = "0";
      document.body.appendChild(ta);
      ta.focus();
      ta.select();
      const ok = document.execCommand("copy");
      document.body.removeChild(ta);
      return ok;
    } catch (e) {
      return false;
    }
  }
  return new Promise(res => {
    if (navigator.clipboard && navigator.clipboard.writeText) navigator.clipboard.writeText(text).then(() => res(true), () => res(fallback()));else res(fallback());
  });
}
function extractJSON(text) {
  const a = text.indexOf("["),
    o = text.indexOf("{");
  const start = a >= 0 && (o < 0 || a < o) ? a : o;
  if (start < 0) throw new Error("응답에서 JSON을 찾지 못했어요");
  const end = Math.max(text.lastIndexOf("]"), text.lastIndexOf("}"));
  return JSON.parse(text.slice(start, end + 1));
}
async function callClaude(content, maxTokens, retried) {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: maxTokens || 2000,
      messages: [{
        role: "user",
        content
      }]
    })
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error.message || "API 오류");
  const text = (data.content || []).filter(b => b.type === "text").map(b => b.text).join("").replace(/```json|```/g, "").trim();
  try {
    return extractJSON(text);
  } catch (e) {
    if (!retried) return callClaude(content, maxTokens, true);
    throw new Error("응답 해석에 실패했어요. 재료를 줄여 다시 시도해 주세요.");
  }
}
function toImageBlock(dataUrl) {
  const m = dataUrl.match(/^data:(image\/[a-z0-9.+-]+);base64,(.*)$/i);
  if (!m) return null;
  return {
    type: "image",
    source: {
      type: "base64",
      media_type: m[1],
      data: m[2]
    }
  };
}
function fileToDataUrl(file) {
  return new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = e => resolve(e.target.result);
    r.onerror = () => reject(new Error("파일 읽기 실패"));
    r.readAsDataURL(file);
  });
}
async function prepareImage(file) {
  const raw = await fileToDataUrl(file);
  const img = await new Promise((res, rej) => {
    const im = new Image();
    im.onload = () => res(im);
    im.onerror = () => rej(new Error("이미지 해석 실패"));
    im.src = raw;
  });
  const MAX = 1200;
  const s = Math.min(1, MAX / Math.max(img.width, img.height));
  const cv = document.createElement("canvas");
  cv.width = Math.max(1, Math.round(img.width * s));
  cv.height = Math.max(1, Math.round(img.height * s));
  const ctx = cv.getContext("2d");
  ctx.fillStyle = "#fff";
  ctx.fillRect(0, 0, cv.width, cv.height);
  ctx.drawImage(img, 0, 0, cv.width, cv.height);
  return cv.toDataURL("image/jpeg", 0.85);
}

